WITH cte_627 AS (SELECT ABS(fel34.c3) AS col_1, (SELECT AVG(s452.c15) AS subq_col FROM t2 AS s452) AS col_2, LOG(fel34.c1) AS col_3 FROM t2 AS fel34 WHERE (fel34.c10 <= NULL)), cte_416 AS (SELECT hzv45.c6 AS col_1, LOG(hzv45.c1) AS col_2, AVG(hzv45.c1) AS col_3 FROM t1 AS hzv45 GROUP BY hzv45.c6, LOG(hzv45.c1)) SELECT DISTINCT MAX(cte.col_2) AS col_1, cte.col_3 AS col_3, cte.col_1 AS col_1_1, STDDEV_SAMP(cte.col_3) AS col_1_2 FROM cte_416 AS cte WHERE ((TAN(cte.col_3) = 35) AND (cte.col_1 <> 'sample_19') AND (cte.col_2 = 74)) GROUP BY cte.col_3, cte.col_1, cte.col_1, cte.col_1 ORDER BY cte.col_1 DESC

WITH cte_147 AS (SELECT BIT_XOR(jxz96.c3) AS col_1, BIT_OR(jxz96.c1) AS col_2, jxz96.c7 AS col_3 FROM t2 AS jxz96 WHERE (jxz96.c9 >= 'sample_60') GROUP BY jxz96.c7), cte_970 AS (SELECT TAN(bia95.c3) AS col_1, SUBSTRING(bia95.c10, 13, 3) AS col_2, MIN(bia95.c12) AS col_3 FROM t3 AS bia95 GROUP BY TAN(bia95.c3), SUBSTRING(bia95.c10, 13, 3)) SELECT DISTINCT ABS(1) AS col_1, ROUND(subq.group_concat_col_3, 5) AS col_1_2, subq.col_2 AS col_2, COUNT(subq.var_samp_col_1) AS col_1_3, subq.var_samp_col_1 AS var_samp_col_1 FROM (SELECT VAR_SAMP(s462.col_1) AS var_samp_col_1, GROUP_CONCAT(s462.col_3 ORDER BY s462.col_3) AS group_concat_col_3, s462.col_2 AS col_2 FROM cte_970 AS s462 GROUP BY s462.col_2 ORDER BY s462.col_2 ASC) AS subq WHERE (subq.group_concat_col_3 <> 'sample_1') GROUP BY ABS(1), subq.var_samp_col_1, ROUND(subq.group_concat_col_3, 5), subq.var_samp_col_1, subq.col_2, subq.var_samp_col_1, subq.var_samp_col_1, subq.var_samp_col_1 ORDER BY subq.var_samp_col_1 ASC

WITH cte_450 AS (SELECT VAR_POP(kqn86.c15) AS col_1, AVG(kqn86.c8) AS col_2 FROM t3 AS kqn86 WHERE kqn86.c1 BETWEEN 17 AND 42), cte_921 AS (SELECT (SELECT VAR_SAMP(85) AS subq_col FROM t2 AS s687) AS col_1, egb12.c10 AS col_2 FROM t2 AS egb12 WHERE egb12.c9 IS NOT NULL) (SELECT DISTINCT SUBSTRING(fhb46.c6, 19, 8) AS col_1, DENSE_RANK() OVER (ORDER BY fhb46.c2 DESC) AS col_2, lku49.col_2 AS col_3 FROM t1 AS fhb46 CROSS JOIN cte_450 AS lku49 ON EXISTS (SELECT rel14.col_1 AS col_1 FROM cte_450 AS rel14 WHERE (fhb46.c4 = rel14.col_1)) LIMIT 4) UNION SELECT sgw23.col_2 AS col_1, sgw23.col_1 AS col_2, sgw23.col_1 AS col_3 FROM cte_921 AS sgw23 WHERE sgw23.col_1 IS NULL

WITH cte_506 AS (SELECT TAN(hri78.c15) AS col_1, hri78.c4 AS col_2, (SELECT s827.c3 AS subq_col FROM t3 AS s827 ORDER BY s827.c3 ASC LIMIT 1) AS col_3, hri78.c11 AS col_4 FROM t3 AS hri78), cte_944 AS (SELECT DENSE_RANK() OVER (ORDER BY ytc30.c6 ASC) AS col_1, LOG(ytc30.c4) AS col_2, SUM(DISTINCT ytc30.c4) AS col_3 FROM t1 AS ytc30 WHERE ytc30.c5 NOT BETWEEN '2023-08-23 07:59:22' AND '2023-03-20 19:09:46' GROUP BY ytc30.c6, LOG(ytc30.c4)) SELECT subq.bit_and_c1 AS bit_and_c1, subq.stddev_samp_c4 AS stddev_samp_c4, subq.stddev_c1 AS stddev_c1, STDDEV(subq.bit_and_c1) AS col_1 FROM (SELECT STDDEV_SAMP(s131.c4) AS stddev_samp_c4, STDDEV(s131.c1) AS stddev_c1, BIT_AND(s131.c1) AS bit_and_c1 FROM t1 AS s131 WHERE (s131.c4 <> 19) GROUP BY s131.c5 LIMIT 8) AS subq WHERE subq.stddev_c1 NOT IN (SELECT subq.col_1 AS col_1 FROM cte_944 AS subq WHERE (subq.col_1 > 14)) GROUP BY subq.bit_and_c1, subq.stddev_c1, subq.stddev_samp_c4, subq.stddev_c1, subq.stddev_c1, subq.stddev_c1 ORDER BY subq.stddev_c1 ASC

