(SELECT qeg57.c14 AS col_1, STD(qeg57.c15) AS col_2, (SELECT VARIANCE(3) AS subq_col FROM t1 AS s123) AS col_3, (SELECT s712.c4 AS subq_col FROM t2 AS s712 ORDER BY s712.c4 ASC LIMIT 1) AS col_4 FROM t3 AS qeg57 LEFT JOIN t1 AS dms99 ON qeg57.c1 BETWEEN dms99.c4 AND dms99.c4 WHERE ((SELECT s132.c14 AS subq_col FROM t3 AS s132 ORDER BY s132.c14 ASC LIMIT 1) = 'sample_78') GROUP BY qeg57.c14, qeg57.c7, qeg57.c7, qeg57.c7 ORDER BY qeg57.c7 ASC) INTERSECT SELECT jtw46.c10 AS col_1, jtw46.c3 AS col_2, 39 AS col_3, 91 AS col_4 FROM t3 AS jtw46 WHERE ((ABS(jtw46.c1) = 31) AND (DATE_FORMAT(jtw46.c5, 'YYYY-MM-DD HH24:MI:SS') <> 'sample_36'))

