WITH cte_61 AS (SELECT STDDEV(hrf15.c2) AS col_1, hrf15.c5 AS col_2 FROM t2 AS hrf15 GROUP BY hrf15.c5), cte_891 AS (SELECT cws71.c2 AS col_1, COS(cws71.c1) AS col_2 FROM t2 AS cws71 WHERE (LENGTH(cws71.c6) <> 42)) SELECT ROW_NUMBER() OVER (ORDER BY 1=1) AS col_1, subq.bit_xor_c4 AS bit_xor_c4, VARIANCE(subq.sum_distinct_c1) AS col_1_2, STDDEV_POP(subq.bit_xor_c4) AS col_1_3, COUNT(DISTINCT subq.bit_xor_c4) AS col_1_4 FROM (SELECT BIT_XOR(s183.c4) AS bit_xor_c4, SUM(DISTINCT s183.c1) AS sum_distinct_c1 FROM t1 AS s183 WHERE (s183.c5 < '2023-01-01 14:18:15') GROUP BY s183.c6 LIMIT 5) AS subq WHERE (subq.sum_distinct_c1 = NULL) GROUP BY subq.bit_xor_c4 LOCK IN SHARE MODE

